    int T;
    if (!(cin >> T)) return 0;
    string line;
    getline(cin, line); // consume end‑of‑line after T
    for (int tc = 0; tc < T; ++tc) {
        getline(cin, line);
        // trim trailing spaces
        while (!line.empty() && line.back() == ' ') line.pop_back();
        // trim leading spaces
        while (!line.empty() && line.front() == ' ') line.erase(line.begin());
        if (line.length() > 5)
            cout << "Long String\n";
        else
            cout << "Short String\n";
    }
    return 0;
}

