import sys

def solve():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    out = []
    for i in range(1, T + 1):
        s = data[i] if i < len(data) else ''
        trimmed = s.strip()
        if len(trimmed) > 5:
            out.append('Long String')
        else:
            out.append('Short String')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

